import { useRef, useState } from "react";

export default function Composer({ onSend, center, disabled }) {
    const [text, setText] = useState("");
    const [file, setFile] = useState(null);
    const fileInputRef = useRef(null);

    const submit = () => {
        if ((!text.trim() && !file) || disabled) return;

        onSend({ text, file });   // send both
        setText("");
        setFile(null);
    };

    const onFileSelect = (e) => {
        const selected = e.target.files[0];
        if (selected) setFile(selected);
    };

    return (
        <div className={`composer ${center ? "center" : "bottom"}`}>

            {/* ➕ Button */}
            <button
                className="plus-btn"
                onClick={() => fileInputRef.current.click()}
                disabled={disabled}
                type="button"
            >
                +
            </button>

            {/* Hidden file input */}
            <input
                type="file"
                ref={fileInputRef}
                hidden
                onChange={onFileSelect}
            />

            {/* Text input */}
            <textarea
                placeholder={disabled ? "AI is thinking..." : "Send a message"}
                value={text}
                disabled={disabled}
                onChange={(e) => setText(e.target.value)}
                onKeyDown={(e) => {
                    if (e.key === "Enter" && !e.shiftKey) {
                        e.preventDefault();
                        submit();
                    }
                }}
            />

            {/* Send */}
            <button onClick={submit} disabled={disabled}>
                ➤
            </button>

            {/* Selected file preview */}
            {file && (
                <div className="file-preview">
                    📎 {file.name}
                </div>
            )}
        </div>
    );
}
